const item = $input.first().json;
const body = item.body || item;
const required = ['engagement_id','asset_id','source_tool','title'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) return [{ json: { valid: false, missing, body } }];
return [{ json: { valid: true, body } }];

const body = $('Validate Schema').first().json.body;

// Severity normalization
const sevMap = {
  critical: 'critical', high: 'high', medium: 'medium', moderate: 'medium',
  low: 'low', info: 'informational', informational: 'informational', note: 'informational'
};
const severity = sevMap[(body.raw_severity || body.severity || 'medium').toLowerCase()] || 'medium';

// CWE mapping from common titles
const cweMap = {
  'sql injection': 'CWE-89', 'xss': 'CWE-79', 'cross-site scripting': 'CWE-79',
  'csrf': 'CWE-352', 'ssrf': 'CWE-918', 'xxe': 'CWE-611',
  'path traversal': 'CWE-22', 'idor': 'CWE-639', 'open redirect': 'CWE-601',
  'csp': 'CWE-693', 'content-security-policy': 'CWE-693',
  'hsts': 'CWE-319', 'strict-transport': 'CWE-319',
  'tls 1.0': 'CWE-326', 'tls 1.1': 'CWE-326', 'ssl': 'CWE-326',
  'version disclosure': 'CWE-200', 'x-frame': 'CWE-1021',
  'clickjacking': 'CWE-1021', 'x-content-type': 'CWE-693'
};
const titleLower = (body.title || '').toLowerCase();
let cweId = body.cwe_id || null;
if (!cweId) {
  for (const [keyword, cwe] of Object.entries(cweMap)) {
    if (titleLower.includes(keyword)) { cweId = cwe; break; }
  }
}

// OWASP mapping
const owaspMap = {
  'CWE-89': 'A03:2021', 'CWE-79': 'A03:2021', 'CWE-352': 'A01:2021',
  'CWE-918': 'A10:2021', 'CWE-611': 'A05:2021', 'CWE-22': 'A01:2021',
  'CWE-639': 'A01:2021', 'CWE-693': 'A05:2021', 'CWE-319': 'A02:2021',
  'CWE-326': 'A02:2021', 'CWE-200': 'A05:2021', 'CWE-1021': 'A04:2021'
};
const owaspCategory = body.owasp_category || (cweId ? owaspMap[cweId] : null);

// Sanitize evidence (remove potential credentials)
let rawEvidence = body.raw_evidence || '';
rawEvidence = rawEvidence.replace(/password["']?\s*[=:]\s*[^\s&"',]+/gi, 'password=[REDACTED]');
rawEvidence = rawEvidence.replace(/authorization:\s*bearer\s+[a-z0-9._-]+/gi, 'Authorization: Bearer [REDACTED]');
rawEvidence = rawEvidence.replace(/api[_-]?key["']?\s*[=:]\s*[^\s&"',]+/gi, 'api_key=[REDACTED]');

return [{ json: {
  engagement_id: body.engagement_id,
  asset_id: body.asset_id,
  source_tool: body.source_tool,
  title: body.title,
  raw_severity: severity,
  raw_evidence: rawEvidence.substring(0, 5000),
  raw_data: body.raw_data || {},
  cwe_id: cweId,
  owasp_category: owaspCategory
} }];
